60	/** Сводка правильного ответа для UI и AI-разбора */
61	export function formatExpectedAnswer(q: IQuestion): string {
62	  const qt = getQuestionType(q);
63	  switch (qt) {
64	    case 'single_choice':
65	      return q.correctOption ?? '';
66	    case 'multiple_choice':
67	      return (q.correctOptions ?? []).join('; ');
68	    case 'matching_single': {
69	      const cm = q.correctMatching ?? {};
70	      const left = q.matchingLeft ?? [];
71	      const right = q.matchingRight ?? [];
72	      const lines = Object.keys(cm).map((lid) => {
73	        const lt = left.find((x) => x.id === lid)?.text ?? lid;
74	        const rid = cm[lid] as string;
75	        const rt = right.find((x) => x.id === rid)?.text ?? rid;
76	        return `${lt} → ${rt}`;
77	      });
78	      return lines.join(' | ');
79	    }
80	    case 'matching_multiple': {
81	      const cm = q.correctMatching ?? {};
82	      const left = q.matchingLeft ?? [];
83	      const right = q.matchingRight ?? [];
84	      const lines = Object.keys(cm).map((lid) => {
85	        const lt = left.find((x) => x.id === lid)?.text ?? lid;
86	        const rids = cm[lid] as string[];
87	        const rt = (rids || []).map((rid) => right.find((x) => x.id === rid)?.text ?? rid).join(', ');
88	        return `${lt} → [${rt}]`;
89	      });
90	      return lines.join(' | ');
91	    }
92	    case 'short_answer':
93	      return (q.acceptableAnswers ?? []).join(' или ');
94	    case 'text_input':
95	      return (
96	        q.referenceAnswer?.trim() ||
97	        (q.acceptableAnswers ?? []).join(' / ') ||
98	        (q.acceptableKeywords ?? []).join(', ')
99	      );
100	    default:
101	      return '';
102	  }
103	}
