105	/**
106	 * Значение для `selectedOption` / состояния ввода на клиенте (как при отправке теста).
107	 * Включать в ответ API только в dev (вместе с correctAnswerHint).
108	 */
109	export function clientPrefillValueForQuestion(q: IQuestion): string {
110	  const qt = getQuestionType(q);
111	  switch (qt) {
112	    case 'single_choice':
113	      return (q.correctOption ?? '').trim();
114	    case 'multiple_choice': {
115	      const co = (q.correctOptions ?? []).filter((x) => String(x).trim());
116	      if (co.length === 0) return '';
117	      return JSON.stringify([...co].map(String).sort());
118	    }
119	    case 'matching_single':
120	    case 'matching_multiple': {
121	      const cm = q.correctMatching;
122	      if (!cm || typeof cm !== 'object') return '';
123	      return JSON.stringify(cm);
124	    }
125	    case 'short_answer': {
126	      const a = (q.acceptableAnswers ?? []).find((x) => String(x).trim());
127	      return a ? String(a).trim() : '';
128	    }
129	    case 'text_input': {
130	      const ref = (q.referenceAnswer ?? '').trim();
131	      if (ref) return ref;
132	      const aa = (q.acceptableAnswers ?? []).find((x) => String(x).trim());
133	      if (aa) return String(aa).trim();
134	      const kw = (q.acceptableKeywords ?? []).find((x) => String(x).trim());
135	      return kw ? String(kw).trim() : '';
136	    }
137	    default:
138	      return (q.correctOption ?? '').trim();
139	  }
140	}
