142	/** Кратко показать ответ пользователя в тексте ошибки */
143	export function summarizeUserAnswer(selectedOption: string): string {
144	  const t = selectedOption.trim();
145	  if (!t) return '(пусто)';
146	  if (t.startsWith('{') || t.startsWith('[')) {
147	    try {
148	      const v = JSON.parse(t) as unknown;
149	      if (Array.isArray(v)) return v.join(', ');
150	      if (v && typeof v === 'object') return JSON.stringify(v);
151	    } catch {
152	      /* fallthrough */
153	    }
154	  }
155	  return t.length > 200 ? `${t.slice(0, 200)}…` : t;
156	}
