158	export function gradeAnswer(question: IQuestion, selectedOption: string): boolean {
159	  const qt = getQuestionType(question);
160	  const raw = selectedOption.trim();
161	
162	  switch (qt) {
163	    case 'single_choice': {
164	      const co = question.correctOption?.trim() ?? '';
165	      return normText(raw) === normText(co);
166	    }
167	    case 'multiple_choice': {
168	      const arr = parseJsonArray(raw);
169	      if (!arr || !arr.every((x) => typeof x === 'string')) return false;
170	      const user = (arr as string[]).map((x) => x.trim());
171	      const correct = question.correctOptions ?? [];
172	      return setsEqualStrings(user, correct);
173	    }
174	    case 'matching_single': {
175	      const userObj = parseJsonObject(raw);
176	      const correct = question.correctMatching ?? {};
177	      if (!userObj) return false;
178	      const keys = Object.keys(correct);
179	      if (keys.length !== Object.keys(userObj).length) return false;
180	      return keys.every((k) => {
181	        const cv = correct[k];
182	        const uv = userObj[k];
183	        return typeof cv === 'string' && typeof uv === 'string' && normText(cv) === normText(uv);
184	      });
185	    }
186	    case 'matching_multiple': {
187	      const userObj = parseJsonObject(raw);
188	      const correct = question.correctMatching ?? {};
189	      if (!userObj) return false;
190	      const keys = Object.keys(correct);
191	      if (keys.length !== Object.keys(userObj).length) return false;
192	      for (const k of keys) {
193	        const cVal = correct[k];
194	        const uVal = userObj[k];
195	        if (!Array.isArray(cVal) || !Array.isArray(uVal)) return false;
196	        if (!cVal.every((x) => typeof x === 'string') || !uVal.every((x) => typeof x === 'string')) {
197	          return false;
198	        }
199	        if (!setsEqualStrings(cVal as string[], uVal as string[])) return false;
200	      }
201	      return true;
202	    }
203	    case 'short_answer': {
204	      const user = normText(raw);
205	      const ok = question.acceptableAnswers ?? [];
206	      return ok.some((a) => normText(a) === user || user.includes(normText(a)));
207	    }
208	    case 'text_input': {
209	      const user = normText(raw);
210	      if (user.length < 2) return false;
211	      const answers = question.acceptableAnswers ?? [];
212	      if (answers.some((a) => normText(a) === user || user.includes(normText(a)))) return true;
213	      const kws = question.acceptableKeywords ?? [];
214	      if (kws.length > 0) {
215	        const hit = kws.filter((k) => user.includes(normText(k))).length;
216	        return hit >= Math.min(kws.length, Math.max(1, Math.ceil(kws.length * 0.6)));
217	      }
218	      const ref = question.referenceAnswer?.trim();
219	      if (ref) {
220	        const nr = normText(ref);
221	        return user === nr || (nr.length > 4 && (user.includes(nr) || nr.includes(user)));
222	      }
223	      return false;
224	    }
225	    default:
226	      return false;
227	  }
228	}
