230	export function sanitizeQuestionForClient(q: IQuestion): Record<string, unknown> {
231	  const qt = getQuestionType(q);
232	  const base: Record<string, unknown> = {
233	    questionType: qt,
234	    questionText: q.questionText,
235	    relatedContent: q.relatedContent
236	  };
237	  switch (qt) {
238	    case 'single_choice':
239	      base.options = q.options ?? [];
240	      break;
241	    case 'multiple_choice':
242	      base.options = q.options ?? [];
243	      break;
244	    case 'matching_single':
245	    case 'matching_multiple':
246	      base.matchingLeft = q.matchingLeft ?? [];
247	      base.matchingRight = q.matchingRight ?? [];
248	      break;
249	    case 'short_answer':
250	      break;
251	    case 'text_input':
252	      break;
253	    default:
254	      break;
255	  }
256	  return base;
257	}
