263	function validateMatchingItems(label: string, items: IMatchingItem[] | undefined, min: number, max: number) {
264	  assert(items && items.length >= min && items.length <= max, `${label}: ожидается ${min}–${max} элементов`);
265	  const ids = items.map((x) => x.id?.trim()).filter(Boolean);
266	  assert(ids.length === items.length, `${label}: у каждого элемента нужен id`);
267	  assert(uniqStrings(ids as string[]).length === ids.length, `${label}: id должны быть уникальными`);
268	}
