270	/** LLM иногда пишет explanation вместо aiExplanation или оставляет пусто */
271	function pickAiExplanation(o: Record<string, unknown>): string {
272	  const candidates = [o.aiExplanation, o.explanation, o.ai_explanation, o.feedback];
273	  for (const c of candidates) {
274	    const v = String(c ?? '').trim();
275	    if (v.length >= 3) return v;
276	  }
277	  return 'Краткое пояснение см. в соответствующем разделе учебника по этой теме.';
278	}
