410	/** Один вопрос обычного теста: single_choice, ровно 4 варианта. Бросает при невалидности. */
411	export function validateRegularQuestion(raw: unknown, index: number): IQuestion {
412	  const o = raw as Record<string, unknown>;
413	  const questionText = String(o.questionText ?? '').trim();
414	  assert(questionText.length >= 5, `Вопрос ${index + 1}: слишком короткий questionText`);
415	  const options = (o.options as string[])?.map((x) => String(x).trim()).filter(Boolean) ?? [];
416	  assert(options.length === 4, `Вопрос ${index + 1}: нужно ровно 4 варианта ответа`);
417	  const correctOption = String(o.correctOption ?? '').trim();
418	  assert(options.includes(correctOption), `Вопрос ${index + 1}: correctOption должен совпадать с одним из options`);
419	  const aiExplanation = pickAiExplanation(o);
420	  const rc = (o.relatedContent as Record<string, unknown>) || {};
421	  const pages = Array.isArray(rc.pages) ? rc.pages.map((p) => Number(p)).filter((n) => !Number.isNaN(n)) : [];
422	  const relatedContent: IRelatedContent = {
423	    pages: pages.length ? pages : [1],
424	    topicTitle: rc.topicTitle != null ? String(rc.topicTitle) : undefined
425	  };
426	  return {
427	    questionType: 'single_choice',
428	    questionText,
429	    options,
430	    correctOption,
431	    aiExplanation,
432	    relatedContent
433	  };
434	}
