449	/**
450	 * Best-effort валидация набора single_choice вопросов (для банка): валидные оставляем,
451	 * невалидные молча отбрасываем. Бросает только если не уцелел ни один вопрос.
452	 */
453	export function parseRegularQuestionsLenient(questions: unknown): IQuestion[] {
454	  if (!Array.isArray(questions)) {
455	    throw new Error('OpenAI response: поле questions отсутствует или не массив.');
456	  }
457	  const valid: IQuestion[] = [];
458	  questions.forEach((raw, index) => {
459	    try {
460	      valid.push(validateRegularQuestion(raw, index));
461	    } catch (e) {
462	      console.warn('[bank] вопрос отброшен при валидации:', (e as Error).message);
463	    }
464	  });
465	  if (valid.length === 0) {
466	    throw new Error('Ни один вопрос не прошёл валидацию (все отброшены).');
467	  }
468	  return valid;
469	}

