490	    contentMetadata: IContentForAI['metadata']
491	  ): Promise<IAIFeedback> {
492	    // Симуляция задержки API
493	    await this.delay(800);
494	
495	    // Подсчитываем правильные ответы
496	    const correctCount = userAnswers.filter(a => a.isCorrect).length;
497	    const totalCount = userAnswers.length;
498	    const scorePercent = Math.round((correctCount / totalCount) * 100);
499	
500	    // Анализируем ошибки
501	    const mistakes: IMistake[] = [];
502	
503	    for (let i = 0; i < userAnswers.length; i++) {
504	      const userAnswer = userAnswers[i];
505	      const correctAnswer = correctAnswers[i];
506	
507	      if (!userAnswer.isCorrect) {
508	        const mistake: IMistake = {
509	          question: userAnswer.question,
510	          explanation: `Ваш ответ: ${summarizeUserAnswer(userAnswer.selectedOption)}. Ожидается: ${correctAnswer.correctSummary}. ${correctAnswer.explanation}`
511	        };
512	        if (contentMetadata.bookTitle?.trim()) {
513	          const rcPages = correctAnswer.relatedContent?.pages;
514	          const pages = rcPages && rcPages.length > 0 ? rcPages : [1];
515	          mistake.whereToRead = {
516	            bookTitle: contentMetadata.bookTitle,
517	            chapterTitle: contentMetadata.chapterTitle || 'Вся книга',
518	            pages,
519	            topicTitle: correctAnswer.relatedContent?.topicTitle
520	          };
521	        }
522	        mistakes.push(mistake);
523	      }
524	    }
525	
526	    // Генерируем общий вывод
527	    let summary = '';
528	    
529	    if (scorePercent >= 90) {
530	      summary = `Отличная работа! Вы ответили правильно на ${correctCount} из ${totalCount} вопросов (${scorePercent}%). Вы демонстрируете отличное понимание материала по теме "${contentMetadata.bookTitle}".`;
531	    } else if (scorePercent >= 70) {
532	      summary = `Хороший результат! Вы ответили правильно на ${correctCount} из ${totalCount} вопросов (${scorePercent}%). Рекомендуем повторить материал по темам, где были допущены ошибки.`;
533	    } else if (scorePercent >= 50) {
534	      summary = `Вы ответили правильно на ${correctCount} из ${totalCount} вопросов (${scorePercent}%). Необходимо более внимательно изучить материал. Обратите особое внимание на разделы, указанные в ошибках ниже.`;
535	    } else {
536	      summary = `Вы ответили правильно на ${correctCount} из ${totalCount} вопросов (${scorePercent}%). Рекомендуем полностью перечитать главу "${contentMetadata.chapterTitle || contentMetadata.bookTitle}" и попробовать пройти тест снова.`;
537	    }
538	
539	    if (mistakes.length > 0) {
540	      summary += ` Всего допущено ошибок: ${mistakes.length}. Подробный разбор ошибок представлен ниже.`;
541	    }
542	
543	    return {
544	      summary,
545	      mistakes
546	    };
547	  }
