566	  private async openAiJsonCompletion(
567	    apiKey: string,
568	    messages: Array<{ role: 'system' | 'user' | 'assistant'; content: string }>,
569	    max_tokens: number,
570	    temperature: number
571	  ): Promise<string> {
572	    const response = await fetch('https://api.openai.com/v1/chat/completions', {
573	      method: 'POST',
574	      headers: {
575	        'Content-Type': 'application/json',
576	        Authorization: `Bearer ${apiKey}`
577	      },
578	      body: JSON.stringify({
579	        model: 'gpt-4o-mini',
580	        temperature,
581	        max_tokens,
582	        response_format: { type: 'json_object' },
583	        messages
584	      })
585	    });
586	
587	    if (!response.ok) {
588	      const errorText = await response.text();
589	      console.error('🤖 [AI] response:error', { status: response.status, errorText });
590	      throw new Error(`OpenAI API error: ${response.status} ${errorText}`);
591	    }
592	
593	    const data = (await response.json()) as {
594	      choices?: Array<{ message?: { content?: string } }>;
595	    };
596	
597	    return data.choices?.[0]?.message?.content ?? '';
598	  }
