600	  /**
601	   * Единый хэш контента теста — источник правды для кэша.
602	   * ВАЖНО: должен возвращать ровно тот же хэш, что и generateTest/generateEntBatchedTest,
603	   * чтобы предгенерационный поиск в кэше совпадал с тем, под которым тест сохранится.
604	   */
605	  computeTestContentHash(
606	    text: string,
607	    profile: TestGenerationProfile = 'ent',
608	    questionCount?: number
609	  ): string {
610	    const p: TestGenerationProfile = profile === 'regular' ? 'regular' : 'ent';
611	    if (p === 'ent' && questionCount != null && questionCount > 10) {
612	      return this.hashContent(JSON.stringify({ v: 3, profile: 'ent', n: questionCount, text }));
613	    }
614	    const expectedN = p === 'regular' ? Math.min(50, Math.max(1, questionCount ?? 10)) : 10;
615	    return this.hashContent(JSON.stringify({ v: 4, profile: p, n: expectedN, text }));
616	  }
