199	  /** Проверить ответы, вернуть userAnswers и счёт */
200	  private checkAnswers(test: any, answers: ISubmitTestDTO['answers']) {
201	    if (answers.length !== test.questions.length) {
202	      throw AppError.badRequest(`Expected ${test.questions.length} answers, received ${answers.length}`);
203	    }
204	
205	    const userAnswers: IUserAnswer[] = [];
206	    let correctCount = 0;
207	
208	    for (const question of test.questions) {
209	      const ua = answers.find((a) => a.questionText === question.questionText);
210	      if (!ua) throw AppError.badRequest(`Missing answer for question: "${question.questionText}"`);
211	
212	      const isCorrect = gradeAnswer(question as IQuestion, ua.selectedOption);
213	      if (isCorrect) correctCount++;
214	      userAnswers.push({ question: question.questionText, selectedOption: ua.selectedOption, isCorrect });
215	    }
216	
217	    const totalQuestions = test.questions.length;
218	    return {
219	      userAnswers,
220	      result: { totalQuestions, correctAnswers: correctCount, scorePercent: Math.round((correctCount / totalQuestions) * 100) }
221	    };
222	  }
