553	  async finishSoloTest(req: Request, res: Response): Promise<void> {
554	    const userId = (req as any).user?.userId;
555	    const { soloSessionId }: { soloSessionId: string } = req.body;
556	
557	    const session = await SoloSession.findById(soloSessionId);
558	    if (!session) throw AppError.notFound('Solo session not found');
559	    if (session.userId.toString() !== userId) throw AppError.forbidden('Access denied');
560	
561	    const test = await Test.findById(session.testId);
562	    if (!test) throw AppError.notFound('Test not found');
563	    if (session.answers.length !== test.questions.length) {
564	      throw AppError.badRequest('Solo session is not complete yet');
565	    }
566	
567	    const finalScore = session.answers.reduce((sum, item) => sum + item.questionScore, 0);
568	    const correctCount = session.answers.filter((item) => item.isCorrect).length;
569	
570	    const createdAttempt = await SoloAttempt.create({
571	      userId,
572	      subjectId: test.subjectId,
573	      bookId: test.bookId,
574	      chapterId: test.chapterId,
575	      dailyPackId: session.dailyPackId,
576	      attemptType: session.attemptType,
577	      finalScore,
578	      correctCount,
579	      answeredCount: session.answers.length,
580	      totalQuestions: test.questions.length
581	    });
582	
583	    const betterCount = await SoloAttempt.countDocuments({
584	      dailyPackId: session.dailyPackId,
585	      attemptType: 'ranked',
586	      $or: [
587	        { finalScore: { $gt: finalScore } },
588	        { finalScore, createdAt: { $lt: createdAttempt.createdAt } }
589	      ]
590	    });
591	
592	    success(res, {
593	      result: {
594	        totalQuestions: test.questions.length,
595	        correctAnswers: correctCount,
596	        scorePercent: Math.round((correctCount / test.questions.length) * 100)
597	      },
598	      solo: {
599	        dailyPackId: session.dailyPackId,
600	        mode: session.mode,
601	        attemptType: session.attemptType,
602	        finalScore,
603	        questionTimeLimitSec: session.questionTimeLimitSec,
604	        rank: session.attemptType === 'ranked' ? betterCount + 1 : null
605	      }
606	    }, 'Solo test finished successfully');
607	  }
