19	function assertSubjectNodeForTrial(subj: any, needTitle: string) {
20	  const book = subj.books?.[0];
21	  if (!book?._id) {
22	    throw AppError.badRequest(`У предмета «${needTitle}» нет учебника`);
23	  }
24	  const chapters = [...(book.chapters || [])].sort((a, b) => (a.order ?? 0) - (b.order ?? 0));
25	  const chapter = chapters[0];
26	  if (!chapter?._id) {
27	    throw AppError.badRequest(`У предмета «${needTitle}» нет глав`);
28	  }
29	  const firstTopic = (chapter.topics || [])[0];
30	  if (!firstTopic?._id) {
31	    throw AppError.badRequest(
32	      `У предмета «${needTitle}» в первой главе нет тем — добавьте тему для привязки к карте знаний`
33	    );
34	  }
35	  return {
36	    bookId: book._id.toString(),
37	    chapterId: chapter._id.toString(),
38	    chapterTitle: chapter.title,
39	    topicTitle: firstTopic.title
40	  };
41	}
