43	export class TrialService {
44	  async getConfig(userId?: string) {
45	    const mainSubjects = await Subject.find({ subjectKind: 'main' })
46	      .sort({ title: 1 })
47	      .select('_id title')
48	      .lean();
49	
50	    const profileSubjects = await Subject.find({ subjectKind: 'profile' })
51	      .sort({ title: 1 })
52	      .select('_id title')
53	      .lean();
54	
55	    let pairedProfileIds: string[] | null = null;
56	    if (userId) {
57	      const user = await User.findById(userId).select('profileSubjectPairId').lean();
58	      const pairId = user?.profileSubjectPairId;
59	      if (pairId) {
60	        const pair = await ProfileSubjectPair.findById(pairId).lean();
61	        if (pair) {
62	          pairedProfileIds = [pair.subject1Id.toString(), pair.subject2Id.toString()];
63	        }
64	      }
65	    }
66	
67	    const trialMainsOk = await Promise.all(
68	      MAIN_TRIAL_TITLES.map((title) =>
69	        Subject.findOne({ subjectKind: 'main', title }).select('_id').lean()
70	      )
71	    ).then((docs) => docs.every((d) => d != null));
72	
73	    return {
74	      mainSubjects,
75	      profileSubjects,
76	      pairedProfileIds,
77	      trialMainsOk,
78	      entTrialInfo: {
79	        mainBlocks: MAIN_TRIAL_BLOCKS,
80	        profileBlockPoints: 50,
81	        profileBlockQuestions: 40
82	      }
83	    };
84	  }
85	
86	  async buildPlan(profileSubjectIds: string[]) {
87	    if (profileSubjectIds.length !== 2) {
88	      throw AppError.badRequest('Нужно выбрать ровно 2 профильных предмета');
89	    }
90	    const uniq = [...new Set(profileSubjectIds.map((id) => String(id).trim()))];
91	    if (uniq.length !== 2) {
92	      throw AppError.badRequest('Профильные предметы должны различаться');
93	    }
94	
95	    const profiles = await Subject.find({
96	      _id: { $in: uniq },
97	      subjectKind: 'profile'
98	    }).lean();
99	    if (profiles.length !== 2) {
100	      throw AppError.badRequest('Указаны неверные профильные предметы');
101	    }
102	
103	    const steps: Array<{
104	      subjectId: string;
105	      subjectTitle: string;
106	      bookId: string;
107	      chapterId: string;
108	      chapterTitle: string;
109	      topicTitle: string;
110	      questionCount: number;
111	      trialBlockLabel: string;
112	      useFullBook: boolean;
113	    }> = [];
114	
115	    for (let i = 0; i < MAIN_TRIAL_TITLES.length; i++) {
116	      const titleNeed = MAIN_TRIAL_TITLES[i];
117	      const subj = await Subject.findOne({
118	        subjectKind: 'main',
119	        title: titleNeed
120	      }).lean();
121	      if (!subj?._id) {
122	        throw AppError.badRequest(
123	          `В каталоге нет основного предмета «${titleNeed}» — импортируйте seed для пробного теста`
124	        );
125	      }
126	      const meta = assertSubjectNodeForTrial(subj, titleNeed);
127	      const blk = MAIN_TRIAL_BLOCKS[i];
128	      steps.push({
129	        subjectId: subj._id.toString(),
130	        subjectTitle: subj.title || titleNeed,
131	        bookId: meta.bookId,
132	        chapterId: meta.chapterId,
133	        chapterTitle: meta.chapterTitle,
134	        topicTitle: meta.topicTitle,
135	        questionCount: blk.questionCount,
136	        trialBlockLabel: blk.blockLabel,
137	        useFullBook: true
138	      });
139	    }
140	
141	    for (const subj of profiles) {
142	      const s = subj as any;
143	      const t = s.title || 'Предмет';
144	      const meta = assertSubjectNodeForTrial(s, t);
145	      steps.push({
146	        subjectId: s._id!.toString(),
147	        subjectTitle: t,
148	        bookId: meta.bookId,
149	        chapterId: meta.chapterId,
150	        chapterTitle: meta.chapterTitle,
151	        topicTitle: meta.topicTitle,
152	        questionCount: 40,
153	        trialBlockLabel: `${t}: 40 вопросов (50 баллов)`,
154	        useFullBook: true
155	      });
156	    }
157	
158	    return { steps };
159	  }
160	}
